import { describe, it, expect, beforeAll } from 'vitest';
import { hashPassword, verifyPassword, validatePasswordStrength, generateSecurePassword } from '../lib/auth';

describe('Auth Utilities', () => {
  describe('hashPassword & verifyPassword', () => {
    it('should hash and verify password correctly', async () => {
      const password = 'TestPass123!';
      const hash = await hashPassword(password);

      expect(hash).toBeDefined();
      expect(hash).not.toBe(password);
      expect(await verifyPassword(password, hash)).toBe(true);
    });

    it('should return false for wrong password', async () => {
      const password = 'TestPass123!';
      const wrongPassword = 'WrongPass123!';
      const hash = await hashPassword(password);

      expect(await verifyPassword(wrongPassword, hash)).toBe(false);
    });

    it('should generate different hashes for same password', async () => {
      const password = 'TestPass123!';
      const hash1 = await hashPassword(password);
      const hash2 = await hashPassword(password);

      expect(hash1).not.toBe(hash2); // Different salts
      expect(await verifyPassword(password, hash1)).toBe(true);
      expect(await verifyPassword(password, hash2)).toBe(true);
    });
  });

  describe('validatePasswordStrength', () => {
    it('should validate strong password', () => {
      const result = validatePasswordStrength('StrongPass123');
      expect(result.valid).toBe(true);
      expect(result.errors).toHaveLength(0);
    });

    it('should reject short password', () => {
      const result = validatePasswordStrength('Short1');
      expect(result.valid).toBe(false);
      expect(result.errors).toContain('La contraseña debe tener al menos 8 caracteres');
    });

    it('should reject password without uppercase', () => {
      const result = validatePasswordStrength('lowercase123');
      expect(result.valid).toBe(false);
      expect(result.errors).toContain('Debe contener al menos una mayúscula');
    });

    it('should reject password without lowercase', () => {
      const result = validatePasswordStrength('UPPERCASE123');
      expect(result.valid).toBe(false);
      expect(result.errors).toContain('Debe contener al menos una minúscula');
    });

    it('should reject password without number', () => {
      const result = validatePasswordStrength('NoNumbersHere');
      expect(result.valid).toBe(false);
      expect(result.errors).toContain('Debe contener al menos un número');
    });
  });

  describe('generateSecurePassword', () => {
    it('should generate password of specified length', () => {
      const password = generateSecurePassword(16);
      expect(password).toHaveLength(16);
    });

    it('should generate different passwords each time', () => {
      const password1 = generateSecurePassword();
      const password2 = generateSecurePassword();
      expect(password1).not.toBe(password2);
    });

    it('should generate valid strong passwords', () => {
      const password = generateSecurePassword(16);
      const validation = validatePasswordStrength(password);
      expect(validation.valid).toBe(true);
    });
  });
});

'use client';

import { useEffect, useState } from 'react';
import { DataTable } from '@/components/admin/DataTable';
import { Button } from '@/components/ui/Button';
import { FormModal } from '@/components/admin/FormModal';
import { Input } from '@/components/ui/Input';
import { ImageUploader } from '@/components/admin/ImageUploader';
import { useToast } from '@/components/ui/Toast';
import { Badge } from '@/components/ui/Badge';
import { Category } from '@/types';

export default function CategoriesPage() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [currentItem, setCurrentItem] = useState<Partial<Category> | null>(null);
  const { addToast } = useToast();

  const fetchCategories = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('/api/categories');
      const data = await res.json();
      setCategories(data);
    } catch (err) {
      addToast('Error al cargar categorías', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchCategories();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const isEditing = !!currentItem?.id;
    const url = isEditing ? `/api/categories/${currentItem.id}` : '/api/categories';
    const method = isEditing ? 'PUT' : 'POST';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(currentItem),
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Error al guardar');
      }

      addToast(isEditing ? 'Categoría actualizada' : 'Categoría creada', 'success');
      setIsModalOpen(false);
      fetchCategories();
    } catch (err: any) {
      addToast(err.message, 'error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('¿Estás seguro de eliminar esta categoría?')) return;

    try {
      const res = await fetch(`/api/categories/${id}`, { method: 'DELETE' });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Error al eliminar');
      }
      addToast('Categoría eliminada', 'success');
      fetchCategories();
    } catch (err: any) {
      addToast(err.message, 'error');
    }
  };

  const columns = [
    {
      header: 'Imagen',
      accessor: (row: Category) => (
        row.image_url ? (
          <img src={row.image_url} alt={row.name} className="w-10 h-10 rounded-lg object-cover" />
        ) : (
          <div className="w-10 h-10 rounded-lg bg-surface-2 flex items-center justify-center text-xs text-muted-2">N/A</div>
        )
      ),
    },
    { header: 'Nombre', accessor: 'name' },
    { header: 'Slug', accessor: 'slug' },
    { 
      header: 'Estado', 
      accessor: (row: Category) => (
        <Badge variant={row.is_active ? 'success' : 'default'}>
          {row.is_active ? 'Activa' : 'Inactiva'}
        </Badge>
      ) 
    },
    {
      header: 'Acciones',
      accessor: (row: Category) => (
        <div className="flex gap-2">
          <Button 
            variant="ghost" 
            size="sm" 
            onClick={(e) => {
              e.stopPropagation();
              setCurrentItem(row);
              setIsModalOpen(true);
            }}
          >
            Editar
          </Button>
          <Button 
            variant="ghost" 
            size="sm" 
            className="text-red-500 hover:text-red-600"
            onClick={(e) => {
              e.stopPropagation();
              handleDelete(row.id);
            }}
          >
            Eliminar
          </Button>
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Categorías</h1>
          <p className="text-muted text-sm">Gestioná las categorías de tu catálogo</p>
        </div>
        <Button onClick={() => { setCurrentItem({ name: '', slug: '', is_active: true }); setIsModalOpen(true); }}>
          + Nueva Categoría
        </Button>
      </div>

      <DataTable
        columns={columns}
        data={categories}
        isLoading={isLoading}
      />

      <FormModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentItem?.id ? 'Editar Categoría' : 'Nueva Categoría'}
        onSubmit={handleSubmit}
        isLoading={isSubmitting}
      >
        <Input
          label="Nombre"
          value={currentItem?.name || ''}
          onChange={(e) => setCurrentItem({ ...currentItem, name: e.target.value })}
          required
        />
        <Input
          label="Slug (URL)"
          value={currentItem?.slug || ''}
          placeholder="nombre-categoria"
          onChange={(e) => setCurrentItem({ ...currentItem, slug: e.target.value })}
        />
        <Input
          label="Descripción"
          value={currentItem?.description || ''}
          onChange={(e) => setCurrentItem({ ...currentItem, description: e.target.value })}
        />
        <ImageUploader
          label="Imagen de Categoría"
          value={currentItem?.image_url || ''}
          onChange={(url) => setCurrentItem({ ...currentItem, image_url: url })}
          folder="categories"
        />
        <div className="flex items-center gap-2 mt-4">
          <input
            type="checkbox"
            id="is_active"
            checked={currentItem?.is_active ?? true}
            onChange={(e) => setCurrentItem({ ...currentItem, is_active: e.target.checked })}
            className="rounded border-border"
          />
          <label htmlFor="is_active" className="text-sm font-medium">Categoría activa</label>
        </div>
      </FormModal>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';

interface ConfigData {
  footer: {
    company: string;
    address: string;
    phone: string;
    email: string;
    socialLinks: {
      facebook: string;
      instagram: string;
      twitter: string;
      whatsapp: string;
    };
  };
  legales: {
    privacyPolicy: string;
    termsOfService: string;
    returnPolicy: string;
    dataUsage: string;
  };
  facturacion: {
    empresa: string;
    cuit: string;
    iva: string;
    direccion: string;
    telefono: string;
    email: string;
    ivaInscripto: boolean;
  };
}

export default function ConfiguracionPage() {
  const [activeTab, setActiveTab] = useState<'footer' | 'legales' | 'facturacion'>('footer');
  const [config, setConfig] = useState<ConfigData>({
    footer: {
      company: 'Micro SaaS Ropa',
      address: 'Av. Principal 123, Ciudad',
      phone: '+54 11 1234-5678',
      email: 'contacto@microsaasropa.com',
      socialLinks: {
        facebook: 'https://facebook.com/microsaasropa',
        instagram: 'https://instagram.com/microsaasropa',
        twitter: 'https://twitter.com/microsaasropa',
        whatsapp: '+5491112345678'
      }
    },
    legales: {
      privacyPolicy: '',
      termsOfService: '',
      returnPolicy: '',
      dataUsage: ''
    },
    facturacion: {
      empresa: '',
      cuit: '',
      iva: 'Responsable Inscripto',
      direccion: '',
      telefono: '',
      email: '',
      ivaInscripto: true
    }
  });
  const [isLoading, setIsLoading] = useState(false);
  const [hasChanges, setHasChanges] = useState(false);

  const handleSave = async () => {
    setIsLoading(true);
    try {
      // Simular guardado
      await new Promise(resolve => setTimeout(resolve, 1500));
      setHasChanges(false);
      // Mostrar mensaje de éxito
    } catch (error) {
      console.error('Error saving config:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const updateConfig = (section: keyof ConfigData, field: string, value: any) => {
    setConfig(prev => ({
      ...prev,
      [section]: {
        ...prev[section],
        [field]: value
      }
    }));
    setHasChanges(true);
  };

  const updateNestedConfig = (section: keyof ConfigData, nestedField: string, field: string, value: any) => {
    if (section !== 'footer' || nestedField !== 'socialLinks') return;
    setConfig(prev => ({
      ...prev,
      footer: {
        ...prev.footer,
        socialLinks: {
          ...prev.footer.socialLinks,
          [field as keyof ConfigData['footer']['socialLinks']]: value as string,
        },
      },
    }));
    setHasChanges(true);
  };

  const tabs: Array<{ id: 'footer' | 'legales' | 'facturacion'; label: string; icon: string }> = [
    { id: 'footer', label: 'Footer y Contacto', icon: '📞' },
    { id: 'legales', label: 'Legales', icon: '⚖️' },
    { id: 'facturacion', label: 'Facturación', icon: '🧾' }
  ];

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight mb-1">Configuración</h1>
          <p className="text-muted text-sm">Gestiona la configuración general de tu tienda.</p>
        </div>
        <div className="flex items-center gap-3">
          {hasChanges && (
            <div className="animate-pulse">
              <Badge variant="warning">Hay cambios sin guardar</Badge>
            </div>
          )}
          <Button
            onClick={handleSave}
            disabled={isLoading || !hasChanges}
            className="bg-accent hover:bg-accent/90 text-white"
          >
            {isLoading ? 'Guardando...' : 'Guardar Cambios'}
          </Button>
        </div>
      </div>

      {/* Tabs Navigation */}
      <div className="border-b border-border">
        <nav className="flex space-x-8">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`py-4 px-1 border-b-2 font-medium text-sm transition-colors ${
                activeTab === tab.id
                  ? 'border-accent text-accent'
                  : 'border-transparent text-muted hover:text-foreground'
              }`}
            >
              <span className="mr-2">{tab.icon}</span>
              {tab.label}
            </button>
          ))}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="space-y-6">
        {activeTab === 'footer' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Información de la Empresa */}
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-foreground">Información de la Empresa</h3>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Nombre de la Empresa
                  </label>
                  <input
                    type="text"
                    value={config.footer.company}
                    onChange={(e) => updateConfig('footer', 'company', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Dirección
                  </label>
                  <input
                    type="text"
                    value={config.footer.address}
                    onChange={(e) => updateConfig('footer', 'address', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Teléfono
                  </label>
                  <input
                    type="tel"
                    value={config.footer.phone}
                    onChange={(e) => updateConfig('footer', 'phone', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Email de Contacto
                  </label>
                  <input
                    type="email"
                    value={config.footer.email}
                    onChange={(e) => updateConfig('footer', 'email', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
              </div>
            </div>

            {/* Redes Sociales */}
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-foreground">Redes Sociales</h3>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Facebook
                  </label>
                  <input
                    type="url"
                    value={config.footer.socialLinks.facebook}
                    onChange={(e) => updateNestedConfig('footer', 'socialLinks', 'facebook', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Instagram
                  </label>
                  <input
                    type="url"
                    value={config.footer.socialLinks.instagram}
                    onChange={(e) => updateNestedConfig('footer', 'socialLinks', 'instagram', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Twitter
                  </label>
                  <input
                    type="url"
                    value={config.footer.socialLinks.twitter}
                    onChange={(e) => updateNestedConfig('footer', 'socialLinks', 'twitter', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    WhatsApp
                  </label>
                  <input
                    type="tel"
                    value={config.footer.socialLinks.whatsapp}
                    onChange={(e) => updateNestedConfig('footer', 'socialLinks', 'whatsapp', e.target.value)}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                  />
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'legales' && (
          <div className="space-y-6">
            <h3 className="text-lg font-semibold text-foreground">Documentación Legal</h3>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {[
                { key: 'privacyPolicy', label: 'Política de Privacidad', icon: '🔒' },
                { key: 'termsOfService', label: 'Términos de Servicio', icon: '📋' },
                { key: 'returnPolicy', label: 'Política de Devolución', icon: '↩️' },
                { key: 'dataUsage', label: 'Uso de Datos', icon: '📊' }
              ].map((doc) => (
                <div key={doc.key} className="space-y-2">
                  <label className="block text-sm font-medium text-foreground flex items-center gap-2">
                    <span>{doc.icon}</span>
                    {doc.label}
                  </label>
                  <textarea
                    value={config.legales[doc.key as keyof typeof config.legales]}
                    onChange={(e) => updateConfig('legales', doc.key, e.target.value)}
                    rows={8}
                    className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent resize-none"
                    placeholder={`Escribe el contenido de ${doc.label.toLowerCase()}...`}
                  />
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'facturacion' && (
          <div className="space-y-6">
            <h3 className="text-lg font-semibold text-foreground">Configuración de Facturación</h3>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Datos Fiscales */}
              <div className="space-y-4">
                <h4 className="text-md font-medium text-foreground">Datos Fiscales</h4>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-2">
                      Razón Social
                    </label>
                    <input
                      type="text"
                      value={config.facturacion.empresa}
                      onChange={(e) => updateConfig('facturacion', 'empresa', e.target.value)}
                      className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-2">
                      CUIT
                    </label>
                    <input
                      type="text"
                      value={config.facturacion.cuit}
                      onChange={(e) => updateConfig('facturacion', 'cuit', e.target.value)}
                      className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-2">
                      Condición IVA
                    </label>
                    <select
                      value={config.facturacion.iva}
                      onChange={(e) => updateConfig('facturacion', 'iva', e.target.value)}
                      className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                    >
                      <option value="Responsable Inscripto">Responsable Inscripto</option>
                      <option value="Monotributo">Monotributo</option>
                      <option value="Exento">Exento</option>
                      <option value="Consumidor Final">Consumidor Final</option>
                    </select>
                  </div>
                </div>
              </div>

              {/* Contacto Fiscal */}
              <div className="space-y-4">
                <h4 className="text-md font-medium text-foreground">Contacto Fiscal</h4>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-2">
                      Dirección Fiscal
                    </label>
                    <input
                      type="text"
                      value={config.facturacion.direccion}
                      onChange={(e) => updateConfig('facturacion', 'direccion', e.target.value)}
                      className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-2">
                      Teléfono Fiscal
                    </label>
                    <input
                      type="tel"
                      value={config.facturacion.telefono}
                      onChange={(e) => updateConfig('facturacion', 'telefono', e.target.value)}
                      className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-foreground mb-2">
                      Email Fiscal
                    </label>
                    <input
                      type="email"
                      value={config.facturacion.email}
                      onChange={(e) => updateConfig('facturacion', 'email', e.target.value)}
                      className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Generador de Facturas */}
            <div className="mt-8 p-6 bg-surface-2 border border-border rounded-xl">
              <h4 className="text-md font-medium text-foreground mb-4">Generador de Facturas</h4>
              <p className="text-sm text-muted-2 mb-4">
                Configura los datos para generar facturas automáticamente cuando se realicen ventas.
              </p>
              <div className="flex items-center gap-4">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={config.facturacion.ivaInscripto}
                    onChange={(e) => updateConfig('facturacion', 'ivaInscripto', e.target.checked)}
                    className="w-4 h-4 text-accent border-border rounded focus:ring-accent"
                  />
                  <span className="text-sm text-foreground">
                    Habilitar generación automática de facturas
                  </span>
                </label>
                <Button
                  variant="outline"
                  className="border-accent text-accent hover:bg-accent hover:text-white"
                >
                  Configurar Plantilla
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { KPICard } from '@/components/admin/KPICard';
import { DataTable } from '@/components/admin/DataTable';
import { Badge } from '@/components/ui/Badge';
import { Chart } from '@/components/admin/Chart';
import { ChartGrid } from '@/components/admin/ChartGrid';
import { 
  ThermometerWidget, 
  DeviceStatsWidget, 
  KeywordsWidget, 
  CategoriesWidget, 
  ActivityWidget 
} from '@/components/admin/Widgets';

interface DashboardData {
  metrics: {
    totalRevenue: number;
    totalSalesCount: number;
