export default function ProductsPage() {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [currentItem, setCurrentItem] = useState<ProductFormState | null>(null);
  const { addToast } = useToast();

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const [pRes, cRes] = await Promise.all([
        fetch('/api/products'),
        fetch('/api/categories')
      ]);
      const pData = await pRes.json();
      const cData = await cRes.json();
      setProducts(pData);
      setCategories(cData);
    } catch (err) {
      addToast('Error al cargar datos', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const isEditing = !!currentItem?.id;
    const url = isEditing ? `/api/products/${currentItem.id}` : '/api/products';
    const method = isEditing ? 'PUT' : 'POST';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(currentItem),
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Error al guardar');
      }

      addToast(isEditing ? 'Producto actualizado' : 'Producto creado', 'success');
      setIsModalOpen(false);
      fetchData();
    } catch (err: any) {
      addToast(err.message, 'error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('¿Estás seguro de eliminar este producto?')) return;

    try {
      const res = await fetch(`/api/products/${id}`, { method: 'DELETE' });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || 'Error al eliminar');
      }
      addToast('Producto eliminado', 'success');
      fetchData();
    } catch (err: any) {
      addToast(err.message, 'error');
    }
  };

  const columns = [
    {
      header: 'Producto',
      accessor: (row: Product) => (
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-surface-2 rounded-lg overflow-hidden border border-border shrink-0">
            {row.product_images?.[0]?.url ? (
              <img src={row.product_images[0].url} alt={row.name} className="w-full h-full object-cover" />
            ) : (
              <div className="w-full h-full flex items-center justify-center text-[10px] text-muted-2">SIN FOTO</div>
            )}
          </div>
          <div className="min-w-0">
            <p className="font-semibold text-foreground truncate">{row.name}</p>
            <p className="text-xs text-muted-2">SKU: {row.sku}</p>
          </div>
        </div>
      ),
    },
    {
      header: 'Categoría',
      accessor: (row: any) => row.categories?.name || 'N/A'
    },
    {
      header: 'Precio',
      accessor: (row: Product) => (
        <div>
          <p className="font-bold">${row.price.toLocaleString()}</p>
          {row.compare_at_price && (
            <p className="text-xs text-muted-2 line-through">${row.compare_at_price.toLocaleString()}</p>
          )}
        </div>
      )
    },
    {
      header: 'Stock',
      accessor: (row: Product) => {
        const isLow = (row.stock ?? 0) <= (row.low_stock_threshold ?? 0);
        return (
          <div className="flex flex-col items-center">
            <span className={`font-bold ${isLow ? 'text-red-500' : 'text-foreground'}`}>{row.stock}</span>
            {isLow && <Badge variant="error">BAJO</Badge>}
          </div>
        );
      }
    },
    {
      header: 'Estado',
      accessor: (row: Product) => (
        <Badge variant={row.is_active ? 'success' : 'default'}>
          {row.is_active ? 'Activo' : 'Inactivo'}
        </Badge>
      )
    },
    {
      header: 'Acciones',
      accessor: (row: Product) => (
        <div className="flex gap-2">
          <Button
            variant="ghost"
            size="sm"
            onClick={(e) => {
              e.stopPropagation();
              setCurrentItem({
                ...row,
                images: row.product_images?.map(img => ({ url: img.url, public_id: img.public_id })) || []
              });
              setIsModalOpen(true);
            }}
          >
            Editar
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="text-red-500 hover:text-red-600"
            onClick={(e) => {
              e.stopPropagation();
              handleDelete(row.id);
            }}
          >
            Eliminar
          </Button>
        </div>
      ),
    },
  ];

  const categoryOptions = [
    { value: '', label: 'Seleccionar Categoría' },
    ...categories.map(c => ({ value: c.id, label: c.name }))
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Productos</h1>
          <p className="text-muted text-sm">Gestioná tu inventario y catálogo de productos</p>
        </div>
        <Button onClick={() => { setCurrentItem({ name: '', price: 0, stock: 0, images: [], is_active: true }); setIsModalOpen(true); }}>
          + Nuevo Producto
        </Button>
      </div>

      <DataTable
        columns={columns}
        data={products}
        isLoading={isLoading}
      />

      <FormModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentItem?.id ? 'Editar Producto' : 'Nuevo Producto'}
        onSubmit={handleSubmit}
        isLoading={isSubmitting}
      >
        <div className="grid grid-cols-2 gap-4">
          <Input
            label="Nombre"
            className="col-span-2"
            value={currentItem?.name || ''}
            onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), name: e.target.value })}
            required
          />
          <Select
            label="Categoría"
            options={categoryOptions}
            value={currentItem?.category_id || ''}
            onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), category_id: e.target.value })}
            required
          />
          <Input
            label="SKU"
            value={currentItem?.sku || ''}
            onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), sku: e.target.value })}
            required
          />
          <Input
            label="Precio de Venta"
            type="number"
            value={currentItem?.price || 0}
            onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), price: Number(e.target.value) })}
            required
          />
          <Input
            label="Precio de Lista (Compara)"
            type="number"
            value={currentItem?.compare_at_price || 0}
            onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), compare_at_price: Number(e.target.value) })}
          />
          <Input
            label="Stock Actual"
            type="number"
            value={currentItem?.stock || 0}
            onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), stock: Number(e.target.value) })}
            required
          />
          <Input
            label="Alerta Stock Bajo (Min)"
            type="number"
            value={currentItem?.low_stock_threshold || 5}
            onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), low_stock_threshold: Number(e.target.value) })}
          />
        </div>

        <Input
          label="Descripción"
          value={currentItem?.description || ''}
          onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), description: e.target.value })}
        />

        <MultiImageUploader
          label="Galería de Imágenes"
          images={currentItem?.images || []}
          onChange={(images) => setCurrentItem({ ...(currentItem ?? {}), images })}
        />

        <div className="grid grid-cols-2 gap-4">
          <div className="flex items-center gap-2 pt-2">
            <input
              type="checkbox"
              id="is_active"
              checked={currentItem?.is_active ?? true}
              onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), is_active: e.target.checked })}
              className="rounded border-border"
            />
            <label htmlFor="is_active" className="text-sm font-medium">Activo</label>
          </div>
          <div className="flex items-center gap-2 pt-2">
            <input
              type="checkbox"
              id="is_featured"
              checked={currentItem?.is_featured ?? false}
              onChange={(e) => setCurrentItem({ ...(currentItem ?? {}), is_featured: e.target.checked })}
              className="rounded border-border"
            />
            <label htmlFor="is_featured" className="text-sm font-medium">Destacado</label>
          </div>
        </div>
      </FormModal>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { DataTable } from '@/components/admin/DataTable';
import { Button } from '@/components/ui/Button';
import { FormModal } from '@/components/admin/FormModal';
import { Input } from '@/components/ui/Input';
import { Select } from '@/components/ui/Select';
import { useToast } from '@/components/ui/Toast';
import { Badge } from '@/components/ui/Badge';
import { Product } from '@/types';

export default function PromotionsPage() {
  const [promotions, setPromotions] = useState<any[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [currentItem, setCurrentItem] = useState<any>(null);
  const { addToast } = useToast();

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const [promosRes, prodRes] = await Promise.all([
        fetch('/api/promotions'),
        fetch('/api/products')
      ]);
      const promosData = await promosRes.json();
      const prodData = await prodRes.json();
      setPromotions(promosData);
      setProducts(prodData);
    } catch (err) {
      addToast('Error al cargar datos', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const isEditing = !!currentItem?.id;
    const url = isEditing ? `/api/promotions/${currentItem.id}` : '/api/promotions';
    const method = isEditing ? 'PUT' : 'POST';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(currentItem),
      });

      if (!res.ok) throw new Error('Error al guardar');

      addToast(isEditing ? 'Promoción actualizada' : 'Promoción creada', 'success');
      setIsModalOpen(false);
      fetchData();
    } catch (err: any) {
      addToast(err.message, 'error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('¿Estás seguro?')) return;
    try {
      await fetch(`/api/promotions/${id}`, { method: 'DELETE' });
      addToast('Promoción eliminada', 'success');
      fetchData();
    } catch (err) {
      addToast('Error al eliminar', 'error');
    }
  };

  const columns = [
    { header: 'Título', accessor: 'title' },
    { header: 'Producto', accessor: (row: any) => row.product?.name || 'Varios' },
    { 
      header: 'Descuento', 
      accessor: (row: any) => row.discount_percent ? `${row.discount_percent}%` : `$${row.discount_amount}` 
    },
    { 
      header: 'Vigencia', 
      accessor: (row: any) => (
        <span className="text-xs">
          {new Date(row.start_date).toLocaleDateString()} - {new Date(row.end_date).toLocaleDateString()}
        </span>
      ) 
    },
    { 
      header: 'Estado', 
      accessor: (row: any) => (
        <Badge variant={row.is_active ? 'success' : 'default'}>
          {row.is_active ? 'Activa' : 'Inactiva'}
        </Badge>
      ) 
    },
    {
      header: 'Acciones',
      accessor: (row: any) => (
        <div className="flex gap-2">
          <Button variant="ghost" size="sm" onClick={() => { setCurrentItem(row); setIsModalOpen(true); }}>Editar</Button>
          <Button variant="ghost" size="sm" className="text-red-500" onClick={() => handleDelete(row.id)}>Borrar</Button>
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Promociones</h1>
          <p className="text-muted text-sm">Gestioná ofertas y descuentos especiales</p>
        </div>
        <Button onClick={() => { setCurrentItem({ title: '', discount_percent: 0, is_active: true }); setIsModalOpen(true); }}>
          + Nueva Promoción
        </Button>
      </div>

      <DataTable columns={columns} data={promotions} isLoading={isLoading} />

      <FormModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentItem?.id ? 'Editar Promoción' : 'Nueva Promoción'}
        onSubmit={handleSubmit}
        isLoading={isSubmitting}
      >
        <Input label="Título de la Promoción" value={currentItem?.title || ''} onChange={(e) => setCurrentItem({ ...currentItem, title: e.target.value })} required />
        <Select
          label="Producto"
          options={[{ value: '', label: 'Seleccionar Producto' }, ...products.map(p => ({ value: p.id, label: p.name }))]}
          value={currentItem?.product_id || ''}
          onChange={(e) => setCurrentItem({ ...currentItem, product_id: e.target.value })}
          required
        />
        <div className="grid grid-cols-2 gap-4">
          <Input label="Desc. Porcentaje (%)" type="number" value={currentItem?.discount_percent || 0} onChange={(e) => setCurrentItem({ ...currentItem, discount_percent: Number(e.target.value) })} />
          <Input label="Desc. Monto ($)" type="number" value={currentItem?.discount_amount || 0} onChange={(e) => setCurrentItem({ ...currentItem, discount_amount: Number(e.target.value) })} />
        </div>
        <div className="grid grid-cols-2 gap-4">
          <Input label="Fecha Inicio" type="date" value={currentItem?.start_date?.split('T')[0] || ''} onChange={(e) => setCurrentItem({ ...currentItem, start_date: e.target.value })} required />
          <Input label="Fecha Fin" type="date" value={currentItem?.end_date?.split('T')[0] || ''} onChange={(e) => setCurrentItem({ ...currentItem, end_date: e.target.value })} required />
        </div>
        <Input label="Descripción" value={currentItem?.description || ''} onChange={(e) => setCurrentItem({ ...currentItem, description: e.target.value })} />
        <div className="flex items-center gap-2 mt-2">
          <input type="checkbox" id="p_active" checked={currentItem?.is_active ?? true} onChange={(e) => setCurrentItem({ ...currentItem, is_active: e.target.checked })} />
          <label htmlFor="p_active" className="text-sm">Promoción activa</label>
        </div>
      </FormModal>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';

interface Role {
  id: string;
  name: string;
  description: string;
  permissions: string[];
  userCount: number;
  createdAt: string;
  isSystem: boolean;
  isActive: boolean;
}

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  roleName: string;
  avatar?: string;
  lastLogin?: string;
  status: 'active' | 'inactive' | 'suspended';
  createdAt: string;
}

export default function RolesPage() {
  const [activeTab, setActiveTab] = useState<'roles' | 'users' | 'permissions'>('roles');
  const [roles, setRoles] = useState<any[]>([]);
  const [users, setUsers] = useState<any[]>([]);
  const [stats, setStats] = useState({ total: 0, active: 0, inactive: 0, totalUsers: 0 });
  const [showCreateRoleForm, setShowCreateRoleForm] = useState(false);
  const [showCreateUserForm, setShowCreateUserForm] = useState(false);
  const [selectedRole, setSelectedRole] = useState<any>(null);
  const [selectedUser, setSelectedUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('/api/roles');
      const data = await res.json();
      setRoles(data.roles || []);
      setUsers(data.users || []);
      setStats(data.stats || { total: 0, active: 0, inactive: 0, totalUsers: 0 });
    } catch (error) {
      console.error('Error fetching roles:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const availablePermissions = [
    { group: 'Usuarios', permissions: ['users.create', 'users.read', 'users.update', 'users.delete'] },
    { group: 'Productos', permissions: ['products.create', 'products.read', 'products.update', 'products.delete'] },
    { group: 'Pedidos', permissions: ['orders.create', 'orders.read', 'orders.update', 'orders.delete'] },
    { group: 'Categorías', permissions: ['categories.create', 'categories.read', 'categories.update', 'categories.delete'] },
    { group: 'Clientes', permissions: ['customers.read', 'customers.update'] },
    { group: 'Configuración', permissions: ['settings.read', 'settings.update'] },
    { group: 'Webhooks', permissions: ['webhooks.create', 'webhooks.read', 'webhooks.update', 'webhooks.delete'] },
    { group: 'Análisis', permissions: ['analytics.read', 'reports.read'] },
    { group: 'Sistema', permissions: ['system.configure', 'system.backup', 'system.restore'] }
  ];

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'active':
        return <Badge variant="success">Activo</Badge>;
      case 'inactive':
        return <Badge variant="default">Inactivo</Badge>;
      case 'suspended':
        return <Badge variant="error">Suspendido</Badge>;
      default:
        return <Badge variant="default">Desconocido</Badge>;
    }
  };

  const getPermissionLabel = (permission: string) => {
    const labels: Record<string, string> = {
      'users.create': 'Crear usuarios',
      'users.read': 'Ver usuarios',
      'users.update': 'Editar usuarios',
      'users.delete': 'Eliminar usuarios',
      'products.create': 'Crear productos',
      'products.read': 'Ver productos',
      'products.update': 'Editar productos',
      'products.delete': 'Eliminar productos',
      'orders.create': 'Crear pedidos',
      'orders.read': 'Ver pedidos',
      'orders.update': 'Editar pedidos',
      'orders.delete': 'Eliminar pedidos',
      'categories.create': 'Crear categorías',
      'categories.read': 'Ver categorías',
      'categories.update': 'Editar categorías',
      'categories.delete': 'Eliminar categorías',
      'customers.read': 'Ver clientes',
      'customers.update': 'Editar clientes',
      'settings.read': 'Ver configuración',
      'settings.update': 'Editar configuración',
      'webhooks.create': 'Crear webhooks',
      'webhooks.read': 'Ver webhooks',
      'webhooks.update': 'Editar webhooks',
      'webhooks.delete': 'Eliminar webhooks',
      'analytics.read': 'Ver análisis',
      'reports.read': 'Ver reportes',
      'system.configure': 'Configurar sistema',
      'system.backup': 'Hacer backup',
      'system.restore': 'Restaurar backup'
    };
    return labels[permission] || permission;
  };

  const handleToggleRole = async (roleId: string) => {
    try {
      // Simular toggle
      await new Promise(resolve => setTimeout(resolve, 500));

      setRoles(prev => prev.map(role => 
        role.id === roleId 
          ? { ...role, isActive: !role.isActive }
          : role
      ));
    } catch (error) {
      console.error('Error toggling role:', error);
    }
  };

  const handleDeleteRole = async (roleId: string) => {
    if (!confirm('¿Estás seguro de que quieres eliminar este rol?')) return;

    try {
      // Simular eliminación
      await new Promise(resolve => setTimeout(resolve, 500));

      setRoles(prev => prev.filter(role => role.id !== roleId));
    } catch (error) {
      console.error('Error deleting role:', error);
    }
  };

  const handleUpdateUserRole = async (userId: string, newRoleId: string) => {
    try {
      // Simular actualización
      await new Promise(resolve => setTimeout(resolve, 500));

      setUsers(prev => prev.map(user => 
        user.id === userId 
          ? { 
              ...user, 
              role: newRoleId,
              roleName: roles.find(r => r.id === newRoleId)?.name || 'Unknown'
            }
          : user
      ));
    } catch (error) {
      console.error('Error updating user role:', error);
    }
  };

  const handleToggleUserStatus = async (userId: string) => {
    try {
      // Simular toggle
      await new Promise(resolve => setTimeout(resolve, 500));

      setUsers(prev => prev.map(user => {
        if (user.id === userId) {
          const newStatus = user.status === 'active' ? 'inactive' : 'active';
          return { ...user, status: newStatus as 'active' | 'inactive' | 'suspended' };
        }
        return user;
      }));
    } catch (error) {
      console.error('Error toggling user status:', error);
    }
  };

  const activeUsers = users.filter(u => u.is_active);
  const inactiveUsers = users.filter(u => !u.is_active);
  const suspendedUsers = users.filter(u => u.status === 'suspended');

  const tabs: Array<{ id: 'roles' | 'users' | 'permissions'; label: string; count: number }> = [
    { id: 'roles', label: 'Roles', count: roles.length },
    { id: 'users', label: 'Usuarios', count: users.length },
    { id: 'permissions', label: 'Permisos', count: availablePermissions.reduce((acc, group) => acc + group.permissions.length, 0) }
  ];

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight mb-1">Roles y Permisos</h1>
          <p className="text-muted text-sm">Gestiona los roles de usuario y sus permisos en el sistema.</p>
        </div>
        <div className="flex items-center gap-3">
          <Button
            onClick={() => setShowCreateRoleForm(!showCreateRoleForm)}
            className="bg-accent hover:bg-accent/90 text-white"
          >
            + Nuevo Rol
          </Button>
          <Button
            onClick={() => setShowCreateUserForm(!showCreateUserForm)}
            variant="outline"
          >
            + Nuevo Usuario
          </Button>
        </div>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Total Roles</span>
            <span className="text-2xl">👥</span>
          </div>
          <div className="text-2xl font-bold text-blue-500">{stats.total}</div>
          <div className="text-xs text-muted-2">Roles configurados</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Usuarios Activos</span>
            <span className="text-2xl">🟢</span>
          </div>
          <div className="text-2xl font-bold text-green-500">{activeUsers.length}</div>
          <div className="text-xs text-muted-2">Usuarios con acceso</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
