'use client';

import { useState, useEffect } from 'react';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';

interface LowStockItem {
  id: string;
  name: string;
  sku: string;
  category: string;
  currentStock: number;
  lowStockThreshold: number;
  minStock: number;
  maxStock: number;
  lastSale: string;
  daysSinceLastSale: number;
  reorderPoint: number;
  reorderQuantity: number;
  supplier: string;
  cost: number;
  price: number;
  status: 'critical' | 'warning' | 'normal';
}

export default function StockBajoPage() {
  const [activeTab, setActiveTab] = useState<'critical' | 'warning' | 'all'>('critical');
  const [stockItems, setStockItems] = useState<any[]>([]);
  const [stats, setStats] = useState({ total: 0, critical: 0, warning: 0 });
  const [isLoading, setIsLoading] = useState(true);
  const [selectedItems, setSelectedItems] = useState<string[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('/api/stock-bajo');
      const data = await res.json();
      setStockItems(data.products || []);
      setStats(data.stats || { total: 0, critical: 0, warning: 0 });
    } catch (error) {
      console.error('Error fetching stock data:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const filteredItems = stockItems.filter(item => {
    if (activeTab === 'critical') return item.status === 'critical';
    if (activeTab === 'warning') return item.status === 'warning';
    return true; // all
  });

  const criticalItems = stockItems.filter(item => item.status === 'critical');
  const warningItems = stockItems.filter(item => item.status === 'warning');
  const normalItems = stockItems.filter(item => item.status === 'normal');

  const tabs: Array<{ id: 'critical' | 'warning' | 'all'; label: string; count: number; color: string }> = [
    { id: 'critical', label: 'Crítico', count: stats.critical, color: 'text-red-500' },
    { id: 'warning', label: 'Advertencia', count: stats.warning, color: 'text-yellow-500' },
    { id: 'all', label: 'Todos', count: stats.total, color: 'text-blue-500' }
  ];

  const handleSelectItem = (itemId: string) => {
    setSelectedItems(prev => 
      prev.includes(itemId) 
        ? prev.filter(id => id !== itemId)
        : [...prev, itemId]
    );
  };

  const handleSelectAll = () => {
    if (selectedItems.length === filteredItems.length) {
      setSelectedItems([]);
    } else {
      setSelectedItems(filteredItems.map(item => item.id));
    }
  };

  const handleReorder = async () => {
    if (selectedItems.length === 0) return;

    setIsProcessing(true);
    try {
      // Simular proceso de reorden
      await new Promise(resolve => setTimeout(resolve, 2000));

      // Actualizar estado de los items seleccionados
      setStockItems(prev => prev.map(item => 
        selectedItems.includes(item.id)
          ? { ...item, status: 'normal' as const, currentStock: item.currentStock + item.reorderQuantity }
          : item
      ));

      setSelectedItems([]);
    } catch (error) {
      console.error('Error reordering items:', error);
    } finally {
      setIsProcessing(false);
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'critical':
        return <Badge variant="error">Crítico</Badge>;
      case 'warning':
        return <Badge variant="warning">Advertencia</Badge>;
      default:
        return <Badge variant="success">Normal</Badge>;
    }
  };

  const getStockPercentage = (current: number, max: number) => {
    return Math.round((current / max) * 100);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight mb-1">Stock Bajo</h1>
          <p className="text-muted text-sm">Gestiona productos con bajo inventario y reordena automáticamente.</p>
        </div>
        <div className="flex items-center gap-3">
          <Button
            onClick={handleReorder}
            disabled={isProcessing || selectedItems.length === 0}
            className="bg-green-500 hover:bg-green-600 text-white"
          >
            {isProcessing ? 'Procesando...' : `Reordenar (${selectedItems.length})`}
          </Button>
        </div>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Stock Crítico</span>
            <span className="text-2xl">🚨</span>
          </div>
          <div className="text-2xl font-bold text-red-500">{stats.critical}</div>
          <div className="text-xs text-muted-2">Productos necesitan reorden urgente</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Advertencia</span>
            <span className="text-2xl">⚠️</span>
          </div>
          <div className="text-2xl font-bold text-yellow-500">{stats.warning}</div>
          <div className="text-xs text-muted-2">Productos con stock bajo</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Total Items</span>
            <span className="text-2xl">📦</span>
          </div>
          <div className="text-2xl font-bold text-blue-500">{stats.total}</div>
          <div className="text-xs text-muted-2">Productos en seguimiento</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Valor Total</span>
            <span className="text-2xl">💰</span>
          </div>
          <div className="text-2xl font-bold text-green-500">
            ${stockItems.reduce((total, item) => total + (item.price * item.stock), 0).toLocaleString('es-AR')}
          </div>
          <div className="text-xs text-muted-2">Valor del inventario actual</div>
        </div>
      </div>

      {/* Tabs Navigation */}
      <div className="border-b border-border">
        <nav className="flex space-x-8">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`py-4 px-1 border-b-2 font-medium text-sm transition-colors flex items-center gap-2 ${
                activeTab === tab.id
                  ? 'border-accent text-accent'
                  : 'border-transparent text-muted hover:text-foreground'
              }`}
            >
              <span>{tab.label}</span>
              <Badge variant="default" className="text-xs">
                {tab.count}
              </Badge>
            </button>
          ))}
        </nav>
      </div>

      {/* Actions Bar */}
      <div className="flex items-center justify-between p-4 bg-surface-2 rounded-lg border border-border">
        <div className="flex items-center gap-4">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              checked={selectedItems.length === filteredItems.length && filteredItems.length > 0}
              onChange={handleSelectAll}
              className="w-4 h-4 text-accent border-border rounded focus:ring-accent"
            />
            <span className="text-sm text-foreground">
              Seleccionar todos ({filteredItems.length})
            </span>
          </label>
          {selectedItems.length > 0 && (
            <span className="text-sm text-muted-2">
              {selectedItems.length} productos seleccionados
            </span>
          )}
        </div>
        <div className="flex items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => setSelectedItems([])}
          >
            Limpiar selección
          </Button>
        </div>
      </div>

      {/* Items Table */}
      <div className="bg-surface border border-border rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-surface-2">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  <input
                    type="checkbox"
                    checked={selectedItems.length === filteredItems.length && filteredItems.length > 0}
                    onChange={handleSelectAll}
                    className="w-4 h-4 text-accent border-border rounded focus:ring-accent"
                  />
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Producto
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  SKU
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Categoría
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Stock Actual
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Mínimo
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Máximo
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Estado
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Última Venta
                </th>
                <th className="px-4 py-3 text-left text-xs font-medium text-muted-2 uppercase tracking-wider">
                  Reordenar
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {filteredItems.map((item) => (
                <tr key={item.id} className="hover:bg-surface-2 transition-colors">
                  <td className="px-4 py-4">
                    <input
                      type="checkbox"
                      checked={selectedItems.includes(item.id)}
                      onChange={() => handleSelectItem(item.id)}
                      className="w-4 h-4 text-accent border-border rounded focus:ring-accent"
                    />
                  </td>
                  <td className="px-4 py-4">
                    <div>
                      <div className="text-sm font-medium text-foreground">{item.name}</div>
                      <div className="text-xs text-muted-2">{item.supplier}</div>
                    </div>
                  </td>
                  <td className="px-4 py-4 text-sm text-muted-2">{item.sku}</td>
                  <td className="px-4 py-4 text-sm text-muted-2">{item.category}</td>
                  <td className="px-4 py-4">
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-medium text-foreground">{item.currentStock}</span>
                      <div className="w-16 bg-surface-2 rounded-full h-2">
                        <div 
                          className={`h-2 rounded-full ${
                            item.status === 'critical' ? 'bg-red-500' :
                            item.status === 'warning' ? 'bg-yellow-500' : 'bg-green-500'
                          }`}
                          style={{ width: `${getStockPercentage(item.currentStock, item.maxStock)}%` }}
                        />
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-4 text-sm text-muted-2">{item.minStock}</td>
                  <td className="px-4 py-4 text-sm text-muted-2">{item.maxStock}</td>
                  <td className="px-4 py-4">{getStatusBadge(item.status)}</td>
                  <td className="px-4 py-4">
                    <div>
                      <div className="text-sm text-foreground">{item.lastSale}</div>
                      <div className="text-xs text-muted-2">Hace {item.daysSinceLastSale} días</div>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <div className="text-sm">
                      <div className="text-muted-2">Punto: {item.reorderPoint}</div>
                      <div className="text-muted-2">Cantidad: {item.reorderQuantity}</div>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Empty State */}
      {filteredItems.length === 0 && (
        <div className="text-center py-12">
          <div className="text-6xl mb-4">✅</div>
          <h3 className="text-lg font-semibold text-foreground mb-2">
            No hay productos con stock bajo
          </h3>
          <p className="text-sm text-muted-2">
            Todos los productos tienen niveles de inventario adecuados.
          </p>
        </div>
      )}
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { DataTable } from '@/components/admin/DataTable';
import { Button } from '@/components/ui/Button';
import { FormModal } from '@/components/admin/FormModal';
import { Input } from '@/components/ui/Input';
import { Select } from '@/components/ui/Select';
import { useToast } from '@/components/ui/Toast';
import { Badge } from '@/components/ui/Badge';

export default function UsersPage() {
  const [users, setUsers] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [currentItem, setCurrentItem] = useState<any>(null);
  const { addToast } = useToast();

  const fetchUsers = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('/api/users');
      setUsers(await res.json());
    } catch (err) { addToast('Error', 'error'); } 
    finally { setIsLoading(false); }
  };

  useEffect(() => { fetchUsers(); }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Logic for update or create (via different endpoints)
    const isEditing = !!currentItem?.id;
    const url = isEditing ? `/api/users/${currentItem.id}` : '/api/auth/register';

    try {
      const res = await fetch(url, {
        method: isEditing ? 'PUT' : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(currentItem),
      });
      if (!res.ok) throw new Error('Error al guardar usuario');
      addToast(isEditing ? 'Usuario actualizado' : 'Usuario creado', 'success');
      setIsModalOpen(false);
      fetchUsers();
    } catch (err) { addToast('Error', 'error'); } 
    finally { setIsSubmitting(false); }
  };

  const columns = [
    { header: 'Nombre', accessor: 'full_name' },
    { header: 'Email', accessor: 'email' },
    { 
      header: 'Rol', 
      accessor: (row: any) => (
        <Badge variant={row.role === 'admin' ? 'info' : 'default'}>{row.role.toUpperCase()}</Badge>
      ) 
    },
    { 
      header: 'Estado', 
      accessor: (row: any) => (
        <Badge variant={row.is_active ? 'success' : 'error'}>{row.is_active ? 'Activo' : 'Inactivo'}</Badge>
      ) 
    },
    {
      header: 'Acciones',
      accessor: (row: any) => (
        <Button variant="ghost" size="sm" onClick={() => { setCurrentItem(row); setIsModalOpen(true); }}>Editar</Button>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Usuarios & Permisos</h1>
          <p className="text-muted text-sm">Gestioná el equipo que opera la plataforma</p>
        </div>
        <Button onClick={() => { setCurrentItem({ full_name: '', email: '', password: '', role: 'operador', is_active: true }); setIsModalOpen(true); }}>
          + Nuevo Usuario
        </Button>
      </div>

      <DataTable columns={columns} data={users} isLoading={isLoading} />

      <FormModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentItem?.id ? 'Editar Usuario' : 'Nuevo Usuario'}
        onSubmit={handleSubmit}
        isLoading={isSubmitting}
      >
        <Input label="Nombre Completo" value={currentItem?.full_name || ''} onChange={(e) => setCurrentItem({ ...currentItem, full_name: e.target.value })} required />
        <Input label="Email" type="email" value={currentItem?.email || ''} onChange={(e) => setCurrentItem({ ...currentItem, email: e.target.value })} required disabled={!!currentItem?.id} />
        {!currentItem?.id && (
          <Input label="Contraseña" type="password" value={currentItem?.password || ''} onChange={(e) => setCurrentItem({ ...currentItem, password: e.target.value })} required />
        )}
        <Select
          label="Rol"
          options={[
            { value: 'operador', label: 'Operador (Estandar)' },
            { value: 'admin', label: 'Administrador (Total)' },
          ]}
          value={currentItem?.role || 'operador'}
          onChange={(e) => setCurrentItem({ ...currentItem, role: e.target.value })}
        />
        <div className="flex items-center gap-2 mt-2">
          <input type="checkbox" id="u_active" checked={currentItem?.is_active ?? true} onChange={(e) => setCurrentItem({ ...currentItem, is_active: e.target.checked })} />
          <label htmlFor="u_active" className="text-sm">Usuario activo</label>
        </div>
      </FormModal>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { DataTable } from '@/components/admin/DataTable';
import { Button } from '@/components/ui/Button';
import { FormModal } from '@/components/admin/FormModal';
import { Input } from '@/components/ui/Input';
import { Select } from '@/components/ui/Select';
import { useToast } from '@/components/ui/Toast';
import { Badge } from '@/components/ui/Badge';

export default function SalesPage() {
  const [sales, setSales] = useState<any[]>([]);
  const [orders, setOrders] = useState<any[]>([]);
  const [products, setProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [currentItem, setCurrentItem] = useState<any>(null);
  const { addToast } = useToast();

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const [sRes, oRes, pRes] = await Promise.all([
        fetch('/api/sales'),
        fetch('/api/orders'),
        fetch('/api/products')
      ]);
      setSales(await sRes.json());
      setOrders(await oRes.json());
      setProducts(await pRes.json());
    } catch (err) { addToast('Error', 'error'); } 
    finally { setIsLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const res = await fetch('/api/sales', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(currentItem),
      });
      if (!res.ok) throw new Error('Error al registrar venta');
      addToast('Venta registrada con éxito', 'success');
      setIsModalOpen(false);
      fetchData();
    } catch (err) { addToast('Error', 'error'); } 
    finally { setIsSubmitting(false); }
  };

  const handleCreateInvoice = async (saleId: string) => {
    try {
      const res = await fetch('/api/invoices', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sale_id: saleId }),
      });
      if (!res.ok) throw new Error('Error al facturar');
      addToast('Factura generada', 'success');
    } catch (err) { addToast('Error', 'error'); }
  };

  const columns = [
    { header: 'ID Venta', accessor: (row: any) => row.id.split('-')[0].toUpperCase() },
    { header: 'Cliente', accessor: 'customer_name' },
    { header: 'Pago', accessor: (row: any) => <Badge variant="info">{row.payment_method.toUpperCase()}</Badge> },
    { header: 'Total', accessor: (row: any) => `$${row.total.toLocaleString()}` },
    { header: 'Fecha', accessor: (row: any) => new Date(row.sale_date).toLocaleDateString() },
    {
      header: 'Factura',
      accessor: (row: any) => (
        <Button variant="ghost" size="sm" onClick={() => handleCreateInvoice(row.id)}>Facturar</Button>
      ),
    },
  ];

  const selectOrder = (orderId: string) => {
    const order = orders.find(o => o.id === orderId);
    if (order) {
      setCurrentItem({
        ...currentItem,
        order_id: orderId,
        customer_name: order.customer_name,
        total: order.total,
        items: order.order_items.map((it: any) => ({
          product_id: it.product_id,
          quantity: it.quantity,
          unit_price: it.unit_price,
          size: it.size,
          color: it.color
        }))
      });
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Ventas</h1>
          <p className="text-muted text-sm">Registro de ventas y facturación</p>
        </div>
        <Button onClick={() => { setCurrentItem({ customer_name: '', payment_method: 'efectivo', items: [], total: 0 }); setIsModalOpen(true); }}>
          + Registrar Venta
        </Button>
      </div>

      <DataTable columns={columns} data={sales} isLoading={isLoading} />

      <FormModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title="Registrar Nueva Venta"
        onSubmit={handleSubmit}
        isLoading={isSubmitting}
      >
        <Select
          label="Vincular con Pedido (Opcional)"
          options={[{ value: '', label: 'Sin vincular' }, ...orders.filter(o => o.status !== 'entregado').map(o => ({ value: o.id, label: `${o.customer_name} - $${o.total}` }))]}
          value={currentItem?.order_id || ''}
          onChange={(e) => selectOrder(e.target.value)}
        />

        <div className="grid grid-cols-2 gap-4">
          <Input label="Nombre Cliente" value={currentItem?.customer_name || ''} onChange={(e) => setCurrentItem({ ...currentItem, customer_name: e.target.value })} required />
          <Select
            label="Método de Pago"
            options={[
              { value: 'efectivo', label: 'Efectivo' },
              { value: 'transferencia', label: 'Transferencia' },
              { value: 'tarjeta', label: 'Tarjeta' },
            ]}
            value={currentItem?.payment_method || 'efectivo'}
            onChange={(e) => setCurrentItem({ ...currentItem, payment_method: e.target.value })}
          />
        </div>

        <div className="space-y-2 pt-4 border-t border-border">
          <h4 className="font-semibold text-sm">Resumen de Venta</h4>
          {currentItem?.items?.map((it: any, idx: number) => {
            const prod = products.find(p => p.id === it.product_id);
            return (
              <div key={idx} className="flex justify-between text-sm py-1">
                <span>{prod?.name} x {it.quantity}</span>
                <span className="font-bold">${(it.quantity * it.unit_price).toLocaleString()}</span>
              </div>
            );
          })}
          <div className="pt-2 border-t border-border flex justify-end">
            <p className="text-xl font-bold">Total a Cobrar: ${currentItem?.total?.toLocaleString() || 0}</p>
          </div>
        </div>
      </FormModal>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';

interface Webhook {
  id: string;
  name: string;
  url: string;
  event: string;
  method: 'POST' | 'GET';
  headers: Record<string, string>;
  isActive: boolean;
  secret: string;
  retryCount: number;
  timeout: number;
  lastTriggered?: string;
  lastStatus?: 'success' | 'failed' | 'pending';
  createdAt: string;
  description: string;
}

interface WebhookLog {
  id: string;
  webhookId: string;
  event: string;
  status: 'success' | 'failed' | 'pending';
  responseCode?: number;
  responseTime: number;
  error?: string;
  payload: unknown;
  timestamp: string;
}

type NewWebhook = {
  name: string;
  url: string;
  event: string;
  method: 'POST' | 'GET';
  headers: Record<string, string>;
  secret: string;
  retryCount: number;
  timeout: number;
  description: string;
};

type ApiWebhook = {
  id: string;
  name: string;
  url: string;
  event: string;
  method: 'POST' | 'GET';
  headers?: Record<string, string>;
  is_active: boolean;
  secret: string;
  retry_count: number;
  timeout: number;
  created_at: string;
  description?: string;
};

type ApiWebhookLog = {
  id: string;
  webhook_id?: string;
  event?: string;
  status?: 'success' | 'failed' | 'pending';
  response_code?: number;
  response_time?: number;
  error?: string;
  payload?: unknown;
  created_at?: string;
};

export default function WebhooksPage() {
  const [activeTab, setActiveTab] = useState<'webhooks' | 'logs'>('webhooks');
  const [webhooks, setWebhooks] = useState<Webhook[]>([]);
  const [webhookLogs, setWebhookLogs] = useState<WebhookLog[]>([]);
  const [stats, setStats] = useState({ total: 0, active: 0, inactive: 0 });
  const [isCreating, setIsCreating] = useState(false);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newWebhook, setNewWebhook] = useState<NewWebhook>({
    name: '',
    url: '',
    event: '',
    method: 'POST',
    headers: {},
    secret: '',
    retryCount: 3,
    timeout: 30000,
    description: ''
  });
  const [isLoading, setIsLoading] = useState(true);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('/api/webhooks');
      const data = await res.json();

      const mappedWebhooks: Webhook[] = ((data.webhooks || []) as ApiWebhook[]).map((w) => ({
        id: w.id,
        name: w.name,
        url: w.url,
        event: w.event,
        method: w.method,
        headers: w.headers || {},
        isActive: Boolean(w.is_active),
        secret: w.secret,
        retryCount: Number(w.retry_count || 0),
        timeout: Number(w.timeout || 0),
        createdAt: w.created_at,
        description: w.description || '',
      }));

      const mappedLogs: WebhookLog[] = ((data.logs || []) as ApiWebhookLog[]).map((log) => ({
        id: log.id,
        webhookId: log.webhook_id || '',
        event: log.event || 'unknown',
        status: log.status || 'pending',
        responseCode: log.response_code,
        responseTime: Number(log.response_time || 0),
        error: log.error,
        payload: log.payload,
        timestamp: log.created_at || new Date().toISOString(),
      }));

      setWebhooks(mappedWebhooks);
      setWebhookLogs(mappedLogs);
      setStats(data.stats || { total: 0, active: 0, inactive: 0 });
    } catch (error) {
      console.error('Error fetching webhooks:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const availableEvents = [
    'order.created',
    'order.updated',
    'order.cancelled',
    'payment.completed',
    'payment.failed',
    'payment.refunded',
    'product.created',
    'product.updated',
    'product.out_of_stock',
    'customer.created',
    'customer.updated',
    'inventory.low_stock'
  ];

  const handleCreateWebhook = async () => {
    setIsCreating(true);
    try {
      // Simular creación
      await new Promise(resolve => setTimeout(resolve, 1500));

      const webhook: Webhook = {
        id: Date.now().toString(),
        ...newWebhook,
        isActive: true,
        createdAt: new Date().toISOString(),
        lastStatus: undefined
      };

      setWebhooks(prev => [...prev, webhook]);
      setNewWebhook({
        name: '',
        url: '',
        event: '',
        method: 'POST',
        headers: {},
        secret: '',
        retryCount: 3,
        timeout: 30000,
        description: ''
      });
      setShowCreateForm(false);
    } catch (error) {
      console.error('Error creating webhook:', error);
    } finally {
      setIsCreating(false);
    }
  };

  const handleToggleWebhook = async (webhookId: string) => {
    try {
      // Simular toggle
      await new Promise(resolve => setTimeout(resolve, 500));

      setWebhooks(prev => prev.map(webhook => 
        webhook.id === webhookId 
          ? { ...webhook, isActive: !webhook.isActive }
          : webhook
      ));
    } catch (error) {
      console.error('Error toggling webhook:', error);
    }
  };

  const handleDeleteWebhook = async (webhookId: string) => {
    if (!confirm('¿Estás seguro de que quieres eliminar este webhook?')) return;

    try {
      // Simular eliminación
      await new Promise(resolve => setTimeout(resolve, 500));

      setWebhooks(prev => prev.filter(webhook => webhook.id !== webhookId));
    } catch (error) {
      console.error('Error deleting webhook:', error);
    }
  };

  const handleTestWebhook = async (webhook: Webhook) => {
    try {
      // Simular test
      await new Promise(resolve => setTimeout(resolve, 1000));

      // Actualizar último estado
      setWebhooks(prev => prev.map(w => 
        w.id === webhook.id 
          ? { 
              ...w, 
              lastTriggered: new Date().toISOString(),
              lastStatus: Math.random() > 0.2 ? 'success' : 'failed'
            }
          : w
      ));

      // Agregar log de prueba
      const testLog: WebhookLog = {
        id: Date.now().toString(),
        webhookId: webhook.id,
        event: 'test',
        status: Math.random() > 0.2 ? 'success' : 'failed',
        responseCode: Math.random() > 0.2 ? 200 : 500,
        responseTime: Math.floor(Math.random() * 1000) + 100,
        payload: { test: true, timestamp: new Date().toISOString() },
        timestamp: new Date().toISOString()
      };

      setWebhookLogs(prev => [testLog, ...prev]);
    } catch (error) {
      console.error('Error testing webhook:', error);
    }
  };

  const getStatusBadge = (status?: string) => {
    switch (status) {
      case 'success':
        return <Badge variant="success">Éxito</Badge>;
      case 'failed':
        return <Badge variant="error">Falló</Badge>;
      case 'pending':
        return <Badge variant="warning">Pendiente</Badge>;
      default:
        return <Badge variant="default">Nunca</Badge>;
    }
  };

  const activeWebhooks = webhooks.filter(w => w.isActive);
  const inactiveWebhooks = webhooks.filter(w => !w.isActive);

  const tabs: Array<{ id: 'webhooks' | 'logs'; label: string; count: number }> = [
    { id: 'webhooks', label: 'Webhooks', count: webhooks.length },
    { id: 'logs', label: 'Logs', count: webhookLogs.length },
  ];

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight mb-1">Webhooks</h1>
          <p className="text-muted text-sm">Gestiona las integraciones automáticas con servicios externos.</p>
        </div>
        <div className="flex items-center gap-3">
          <Button
            onClick={() => setShowCreateForm(!showCreateForm)}
            className="bg-accent hover:bg-accent/90 text-white"
          >
            + Nuevo Webhook
          </Button>
        </div>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Activos</span>
            <span className="text-2xl">🟢</span>
          </div>
          <div className="text-2xl font-bold text-green-500">{stats.active}</div>
          <div className="text-xs text-muted-2">Webhooks funcionando</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Inactivos</span>
            <span className="text-2xl">🔴</span>
          </div>
          <div className="text-2xl font-bold text-red-500">{stats.inactive}</div>
          <div className="text-xs text-muted-2">Webhooks desactivados</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Total</span>
            <span className="text-2xl">📊</span>
          </div>
          <div className="text-2xl font-bold text-blue-500">{stats.total}</div>
          <div className="text-xs text-muted-2">Todos los webhooks</div>
        </div>

        <div className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-medium text-muted-2">Ejecuciones Hoy</span>
            <span className="text-2xl">📈</span>
          </div>
          <div className="text-2xl font-bold text-purple-500">
            {webhookLogs.filter(log => 
              new Date(log.timestamp).toDateString() === new Date().toDateString()
            ).length}
          </div>
          <div className="text-xs text-muted-2">Webhooks ejecutados hoy</div>
        </div>
      </div>

      {/* Create Webhook Form */}
      {showCreateForm && (
        <div className="bg-surface-2 border border-border rounded-xl p-6">
          <h3 className="text-lg font-semibold text-foreground mb-4">Crear Nuevo Webhook</h3>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                Nombre
              </label>
              <input
                type="text"
                value={newWebhook.name}
                onChange={(e) => setNewWebhook(prev => ({ ...prev, name: e.target.value }))}
                className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                placeholder="Ej: Nueva Orden"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                URL
              </label>
              <input
                type="url"
                value={newWebhook.url}
                onChange={(e) => setNewWebhook(prev => ({ ...prev, url: e.target.value }))}
                className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
                placeholder="https://api.mi-sistema.com/webhook"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                Evento
              </label>
              <select
                value={newWebhook.event}
                onChange={(e) => setNewWebhook(prev => ({ ...prev, event: e.target.value }))}
                className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
              >
                <option value="">Seleccionar evento...</option>
                {availableEvents.map(event => (
                  <option key={event} value={event}>{event}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                Método HTTP
              </label>
              <select
                value={newWebhook.method}
                onChange={(e) => setNewWebhook(prev => ({ ...prev, method: e.target.value as 'POST' | 'GET' }))}
                className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
              >
                <option value="POST">POST</option>
                <option value="GET">GET</option>
              </select>
            </div>
            <div className="lg:col-span-2">
              <label className="block text-sm font-medium text-foreground mb-2">
                Descripción
              </label>
              <textarea
                value={newWebhook.description}
                onChange={(e) => setNewWebhook(prev => ({ ...prev, description: e.target.value }))}
                rows={3}
                className="w-full px-3 py-2 border border-border rounded-lg bg-surface text-foreground focus:outline-none focus:ring-2 focus:ring-accent resize-none"
                placeholder="Describe para qué sirve este webhook..."
              />
            </div>
          </div>
          <div className="flex items-center gap-3 mt-4">
            <Button
              onClick={handleCreateWebhook}
              disabled={isCreating || !newWebhook.name || !newWebhook.url || !newWebhook.event}
              className="bg-accent hover:bg-accent/90 text-white"
            >
              {isCreating ? 'Creando...' : 'Crear Webhook'}
            </Button>
            <Button
              variant="outline"
              onClick={() => setShowCreateForm(false)}
            >
              Cancelar
            </Button>
          </div>
        </div>
      )}

      {/* Tabs Navigation */}
      <div className="border-b border-border">
        <nav className="flex space-x-8">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`py-4 px-1 border-b-2 font-medium text-sm transition-colors flex items-center gap-2 ${
                activeTab === tab.id
                  ? 'border-accent text-accent'
                  : 'border-transparent text-muted hover:text-foreground'
              }`}
            >
              <span>{tab.label}</span>
              <Badge variant="default" className="text-xs">
                {tab.count}
              </Badge>
            </button>
          ))}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="space-y-6">
        {activeTab === 'webhooks' && (
          <div className="space-y-4">
            {webhooks.map((webhook) => (
              <div key={webhook.id} className="bg-surface border border-border rounded-xl p-6 hover:shadow-lg transition-all duration-300">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex-1">
                    <div className="flex items-center gap-3 mb-2">
                      <h3 className="text-lg font-semibold text-foreground">{webhook.name}</h3>
                      <Badge variant={webhook.isActive ? 'success' : 'default'}>
                        {webhook.isActive ? 'Activo' : 'Inactivo'}
                      </Badge>
                      {webhook.lastStatus && getStatusBadge(webhook.lastStatus)}
                    </div>
                    <p className="text-sm text-muted-2 mb-3">{webhook.description}</p>
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 text-sm">
                      <div>
                        <span className="text-muted-2">URL:</span>
                        <div className="font-mono text-foreground break-all">{webhook.url}</div>
                      </div>
                      <div>
                        <span className="text-muted-2">Evento:</span>
                        <div className="font-mono text-foreground">{webhook.event}</div>
                      </div>
                      <div>
                        <span className="text-muted-2">Método:</span>
                        <div className="font-mono text-foreground">{webhook.method}</div>
                      </div>
                      <div>
                        <span className="text-muted-2">Reintentos:</span>
                        <div className="font-mono text-foreground">{webhook.retryCount}</div>
                      </div>
                      {webhook.lastTriggered && (
                        <div>
